// TypeScript: Session ID returned on ResultMessage
const result = await agent.query(prompt);
const sessionId = result.sessionId; // Save this ID

// TypeScript: Use resume option with session ID
const result = await agent.query(prompt, {
  resume: sessionId
});

// TypeScript: Implement SessionStore interface
import { SessionStore, Session } from "@anthropic-ai/claude-agent-sdk";

class RedisSessionStore implements SessionStore {
  async get(sessionId: string): Promise<Session | null> {
    // Redis lookup
    return await redis.get(sessionId);
  }

  async set(sessionId: string, session: Session): Promise<void> {
    // Redis save
    await redis.set(sessionId, session);
  }

  async delete(sessionId: string): Promise<void> {
    // Redis delete
    await redis.del(sessionId);
  }
}

// Use with agent
const agent = new Agent({ sessionStore: new RedisSessionStore() });

// TypeScript: Maintain session continuity
const sessionId = result.sessionId;

// Next interaction
const nextResult = await agent.query(prompt, { resume: sessionId });
